package main

import (
    "fmt"
    "net/http"
    "strings"
)

// ---- Simple router ----
type Router struct {
    routes map[string]http.HandlerFunc
}

func NewRouter() *Router {
    return &Router{
        routes: make(map[string]http.HandlerFunc),
    }
}

func (r *Router) Handle(path string, handler http.HandlerFunc) {
    r.routes[path] = handler
}

func (r *Router) ServeHTTP(w http.ResponseWriter, req *http.Request) {
    path := req.URL.Path

    // Check for exact match
    if handler, ok := r.routes[path]; ok {
        handler(w, req)
        return
    }

    // Check for prefix match
    for route, handler := range r.routes {
        if strings.HasPrefix(path, route) && route != "/" {
            handler(w, req)
            return
        }
    }

    http.NotFound(w, req)
}

func main() {
    // ---- Create router ----
    router := NewRouter()

    // ---- Register routes ----
    router.Handle("/", func(w http.ResponseWriter, r *http.Request) {
        fmt.Fprintf(w, "Home Page")
    })

    router.Handle("/api", func(w http.ResponseWriter, r *http.Request) {
        fmt.Fprintf(w, "API Root")
    })

    router.Handle("/api/users", func(w http.ResponseWriter, r *http.Request) {
        fmt.Fprintf(w, "Users endpoint")
    })

    router.Handle("/api/players", func(w http.ResponseWriter, r *http.Request) {
        // ---- Method-based routing ----
        switch r.Method {
        case "GET":
            fmt.Fprintf(w, "Get all players")
        case "POST":
            fmt.Fprintf(w, "Create a player")
        default:
            http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
        }
    })

    router.Handle("/api/players/", func(w http.ResponseWriter, r *http.Request) {
        // ---- Path parameter extraction ----
        parts := strings.Split(r.URL.Path, "/")
        if len(parts) > 3 {
            id := parts[3]
            fmt.Fprintf(w, "Player ID: %s", id)
        } else {
            fmt.Fprintf(w, "Missing player ID")
        }
    })

    // ---- Start server ----
    fmt.Println("Server starting on :8080")
    fmt.Println("Routes:")
    fmt.Println("  /")
    fmt.Println("  /api")
    fmt.Println("  /api/users")
    fmt.Println("  /api/players (GET, POST)")
    fmt.Println("  /api/players/{id}")

    http.ListenAndServe(":8080", router)
}

// ---- Run with ----
// go run main.go
// curl http://localhost:8080/
// curl http://localhost:8080/api
// curl http://localhost:8080/api/users
// curl http://localhost:8080/api/players
// curl -X POST http://localhost:8080/api/players
// curl http://localhost:8080/api/players/123

